import{_ as a,o as i,c as e,ae as t}from"./chunks/framework.EHGTsUvI.js";const c=JSON.parse('{"title":"解密“模型”与“参数”：从权重到量化部署","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/what-is-model.md","filePath":"ai-tutorial/what-is-model.md"}'),r={name:"ai-tutorial/what-is-model.md"};function o(h,l,s,n,u,d){return i(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="解密-模型-与-参数-从权重到量化部署" tabindex="-1">解密“模型”与“参数”：从权重到量化部署 <a class="header-anchor" href="#解密-模型-与-参数-从权重到量化部署" aria-label="Permalink to &quot;解密“模型”与“参数”：从权重到量化部署&quot;">​</a></h1><blockquote><p>很多人第一次下载模型权重时都会有点错愕：代码没多少，真正占地方的是那一大堆你乍看完全看不懂的数值文件。 也就是从这一步开始，所谓“模型”这件事会突然变得非常具体。它不再只是一个抽象能力名词，而是一份会占磁盘、吃显存、决定部署成本的真实工程对象。</p></blockquote><div class="info custom-block"><p class="custom-block-title">这篇文章重点</p><ul><li>参数究竟是什么</li><li>参数量为什么会和存储、显存直接相关</li><li>FP16、BF16、INT8、INT4 等精度为什么重要</li><li>量化适合什么场景，不适合什么场景</li></ul></div><h2 id="_1-模型在工程上首先是一组权重" tabindex="-1">1. 模型在工程上首先是一组权重 <a class="header-anchor" href="#_1-模型在工程上首先是一组权重" aria-label="Permalink to &quot;1. 模型在工程上首先是一组权重&quot;">​</a></h2><p>从工程角度看，模型不是“写满业务规则的代码”，而是一组巨大的参数权重。</p><p>这些参数本质上是：</p><ul><li>矩阵</li><li>向量</li><li>层与层之间的数值连接关系</li></ul><p>也就是说，模型的“能力”并不是写在 <code>if-else</code> 里，而是分布在海量数值之中。</p><h2 id="_2-为什么参数量直接影响部署成本" tabindex="-1">2. 为什么参数量直接影响部署成本 <a class="header-anchor" href="#_2-为什么参数量直接影响部署成本" aria-label="Permalink to &quot;2. 为什么参数量直接影响部署成本&quot;">​</a></h2><p>参数量越大，通常意味着：</p><ul><li>模型文件越大</li><li>加载所需内存或显存越高</li><li>推理时带宽压力更大</li></ul><p>这也是为什么“7B”和“70B”不只是抽象数字，而会直接决定：</p><ul><li>单卡能不能装下</li><li>服务要不要分片</li><li>成本大概落在哪个量级</li></ul><h2 id="_3-精度为什么重要" tabindex="-1">3. 精度为什么重要 <a class="header-anchor" href="#_3-精度为什么重要" aria-label="Permalink to &quot;3. 精度为什么重要&quot;">​</a></h2><p>模型权重需要用某种数值精度存储，例如：</p><ul><li>FP16</li><li>BF16</li><li>INT8</li><li>INT4</li></ul><p>精度越高，通常保真度越好，但占用资源也越多；精度越低，存储和推理成本下降，但可能带来能力损失。</p><h2 id="_4-量化在解决什么问题" tabindex="-1">4. 量化在解决什么问题 <a class="header-anchor" href="#_4-量化在解决什么问题" aria-label="Permalink to &quot;4. 量化在解决什么问题&quot;">​</a></h2><p>量化的核心目标是：<strong>用更少的存储和显存，承载尽量接近原模型的能力</strong>。</p><p>它最直接的收益包括：</p><ul><li>降低显存占用</li><li>提升部署可行性</li><li>在一定条件下改善吞吐和成本</li></ul><p>但量化不是零代价优化。常见代价是：</p><ul><li>精度下降</li><li>某些复杂推理任务更容易退化</li><li>不同量化方法效果差异明显</li></ul><h2 id="_5-一个实用判断" tabindex="-1">5. 一个实用判断 <a class="header-anchor" href="#_5-一个实用判断" aria-label="Permalink to &quot;5. 一个实用判断&quot;">​</a></h2><p>如果你的场景是：</p><ul><li>信息抽取</li><li>分类</li><li>检索辅助</li><li>流水线中间步骤</li></ul><p>更激进的量化通常更容易接受。</p><p>如果你的场景是：</p><ul><li>复杂推理</li><li>高质量生成</li><li>代码或数学任务</li></ul><p>就应该更谨慎评估量化带来的精度损失。</p><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>理解“模型”最重要的一点是：它本质上是一组庞大的数值权重。参数量、精度和量化方式，会直接影响部署可行性、成本和质量边界。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://huggingface.co/docs/transformers/index" target="_blank" rel="noreferrer">Hugging Face Transformers</a></li><li>延伸阅读：<a href="./hardware-and-compute.html">什么是算力与硬件？</a></li></ul>',34)])])}const _=a(r,[["render",o]]);export{c as __pageData,_ as default};
